```
use std::collections::HashMap;
use std::sync::{Arc, Mutex};

fn can_func_be_pushed(sf: &ScalarFunction, store_type: kv::StoreType) -> bool {
    // Use the failpoint to control whether to push down an expression in the integration test.
    // Push down all expression if the `failpoint expression` is `all`, otherwise, check
    // whether scalar function's name is contained in the enabled expression list (e.g.`ne,eq,lt`).
    // If neither of the above is true, switch to original logic.
    failpoint::inject("PushDownTestSwitcher", |val| {
        let enabled = val.as_string();
        if enabled == "all" {
            return true;
        }
        let exprs: Vec<&str> = enabled.split(",").collect();
        for expr in exprs {
            if expr.trim().to_lowercase() == sf.func_name.l {
                return true;
            }
        }
        return false;
    });

    let mut ret = false;

    match store_type {
        kv::StoreType::TiFlash => {
            ret = scalar_expr_supported_by_flash(sf);
        }
        kv::StoreType::TiKV => {
            ret = scalar_expr_supported_by_tikv(sf);
        }
        kv::StoreType::TiDB => {
            ret = scalar_expr_supported_by_tidb(sf);
        }
        kv::StoreType::UnSpecified => {
            ret = scalar_expr_supported_by_tidb(sf)
                || scalar_expr_supported_by_tikv(sf)
                || scalar_expr_supported_by_flash(sf);
        }
    }

    if ret {
        ret = is_push_down_enabled(sf.func_name.l, store_type);
    }
    return ret;
}

fn store_type_mask(store_type: kv::StoreType) -> u32 {
    if store_type == kv::StoreType::UnSpecified {
        return 1 << kv::StoreType::TiKV as u32
            | 1 << kv::StoreType::TiFlash as u32
            | 1 << kv::StoreType::TiDB as u32;
    }
    return 1 << store_type as u32;
}

// IsPushDownEnabled returns true if the input expr is not in the expr_pushdown_blacklist
fn is_push_down_enabled(name: String, store_type: kv::StoreType) -> bool {
    let default_expr_pushdown_blacklist: Arc<Mutex<HashMap<String, u32>>> =
        DefaultExprPushDownBlacklist.load();
    let value = default_expr_pushdown_blacklist
        .lock()
        .unwrap()
        .get(name.as_str())
        .unwrap_or(0);
    let mask = store_type_mask(store_type);
    !(value & mask == mask)
}
```

