```
public static String doAES(String param, String aesKey, String method) {



 byte[] key = new byte[0];
 byte[] paramByte = new byte[0];
 String finalParam = "";



 try {



 key = (aesKey).getBytes("UTF-8");
 SecretKeySpec secretKeySpec = new SecretKeySpec(key, "AES");
 Cipher cipher = Cipher.getInstance("AES");



 if (method.equals("encrypt")) {
 cipher.init(Cipher.ENCRYPT\_MODE, secretKeySpec);
 paramByte = cipher.doFinal(param.getBytes());
 finalParam = Base64.getEncoder().encodeToString(paramByte);
 } else {
 cipher.init(Cipher.DECRYPT\_MODE, secretKeySpec);
 paramByte = cipher.doFinal(Base64.getDecoder().decode(param));
 finalParam = new String(paramByte);
 }



 } catch(GeneralSecurityException ex) {
 System.out.println("Could not retrieve AES cipher.");
 } catch (UnsupportedEncodingException ex) {
 System.out.println("Cannot use UTF-8 encoding.");
 }



 return finalParam;
 }
```

